import type { AvatarCompactProps, AvatarImageEmits, AvatarUi } from '@soybeanjs/headless/avatar';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Avatar component.
 */
export interface AvatarProps extends AvatarCompactProps {
  /**
   * root class
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<AvatarUi>;
}

/**
 * Events for the Avatar component.
 */
export type AvatarEmits = AvatarImageEmits;

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const avatarVariants = scv({
  slots: {
    root: 'relative flex shrink-0 overflow-hidden rounded-full',
    fallback: 'flex justify-center items-center w-full h-full rounded-full bg-muted font-medium',
    image: 'aspect-square w-full h-full object-cover m-0'
  },
  variants: {
    size: {
      xs: {
        root: 'size-6'
      },
      sm: {
        root: 'size-8'
      },
      md: {
        root: 'size-10'
      },
      lg: {
        root: 'size-12'
      },
      xl: {
        root: 'size-14'
      },
      '2xl': {
        root: 'size-16'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});
